 * checkout. Returns undefined when not found (e.g. a bundled single-file
 * install), letting callers fall back to ~/code or the published gh: template.
 */
function resolveVendoredTemplate(name: string): string | undefined {
  let dir: string;
  try {
    dir = dirname(fileURLToPath(import.meta.url));
  } catch {
    return undefined;
  }
  for (let i = 0; i < 8; i++) {
    const candidate = join(dir, "templates", name);
    if (existsSync(join(candidate, "copier.yml"))) return candidate;
    const parent = dirname(dir);
    if (parent === dir) break;
    dir = parent;
  }
  return undefined;
}

/**
 * Invokes `copier copy gh:delorenj/hermes-agent-template ./agents/hermes/<role>`
 * with the collected --data flags.  Telegram and email steps are *always*
 * skipped here — the recipe's later commands (WireTelegram, WireEmail) handle
 * them in a TUI-friendly way after the bulk provisioning is done.
 *
 * Honors dryRun: prints what would run, doesn't execute copier.
 */
export class RunCopierTemplate extends Command {
  async invoke(): Promise<InvokeResult> {
    const ctx = this.context as HermesAgentContext;
    const { targetRepo, role, agentPurpose, soulTone, modelProvider, modelName } = ctx;
    const ticketProvider = ctx.ticketProvider ?? "plane";
    const profileName =
      ctx.profileName ?? (targetRepo && role ? deriveProfileName(targetRepo, role) : undefined);
    // with_scrum_master is a pm-only copier question; passing it for other
    // roles is harmless (copier ignores it via its `when:` guard).
    const withScrumMaster = role === "pm" && ctx.withScrumMaster === true;

    if (!targetRepo || !role) {
      return {
        success: false,
        message: "PromptForAgentConfig must run before RunCopierTemplate (targetRepo/role unset)",
      };
    }

    const roleDir = join(ctx.targetDir, "agents", "hermes", role);
    ctx.roleDir = roleDir;
    // Derive runtime repo name upfront so PrintHermesSummary can show it
    // even in dry-run mode (where copier never executes).
    ctx.runtimeRepo = `delorenj/agent-hm-${targetRepo}-${role}`;

    // Sanity: copier on PATH?
    const which = spawnSync("which", ["copier"], { encoding: "utf8" });
    if (which.status !== 0) {
      return {
        success: false,
        message:
          "✗ copier not found on PATH.  Install with: `uv tool install copier` or `pip install copier`",
      };
    }

    // Idempotency: if role.yaml already exists, copier will refuse to
    // overwrite without --force.  In --yes mode we automatically re-render
    // (idempotent refresh); otherwise we ask.
    if (existsSync(join(roleDir, "role.yaml")) && !ctx.force) {
      if (ctx.yes) {
        ctx.force = true;
      } else {
        const proceed = await p.confirm({
          message: `${role}/role.yaml already exists — re-render with --overwrite?`,
          initialValue: false,
        });
        if (p.isCancel(proceed) || !proceed) {
          return {
            success: false,
            message: `Skipped: ${roleDir} already provisioned (use --force to re-render)`,
          };
        }
        ctx.force = true;
      }
    }

    // Always set these via env so the post-gen scripts in the copier template
    // skip the bits we'll handle in our own commands.
    const env = {
      ...process.env,
      SKIP_TELEGRAM: "1",
      SKIP_EMAIL: "1",
      // We DO want copier to run runtime-repo + plane + bloodbank + systemd.
      SKIP_RUNTIME_REPO: ctx.skipRuntimeRepo ? "1" : "0",
      SKIP_PLANE: ctx.skipPlane ? "1" : "0",
      SKIP_BLOODBANK: ctx.skipBloodbank ? "1" : "0",
      SKIP_SYSTEMD: ctx.skipSystemd ? "1" : "0",
    };

    // Prefer a local template checkout (if present) so fixes propagate
    // immediately without waiting for a GitHub push. Resolve against $HOME so
    // this works on any operator's machine (e.g. a friend's Mac), not just the
    // box this was authored on. PJANGLER_HERMES_TEMPLATE overrides; otherwise
    // fall back to the published gh: template.
    // Resolution order: explicit env override → vendored submodule (the
    // version-locked default) → a ~/code dev checkout → the published gh:
    // template. PJANGLER_HERMES_TEMPLATE stays the escape hatch for pointing at
    // a live ~/code checkout during template development.
    const LOCAL_TEMPLATE = join(homedir(), "code", "hermes-agent-template");
    const vendored = resolveVendoredTemplate("hermes-agent");
    const templateSrc =
      process.env.PJANGLER_HERMES_TEMPLATE ||
      vendored ||
      (existsSync(join(LOCAL_TEMPLATE, "copier.yml")) ? LOCAL_TEMPLATE : HERMES_AGENT_TEMPLATE);

    const args = [
      "copy",
      templateSrc,
      roleDir,
      "--data", `target_repo=${targetRepo}`,
      "--data", `role=${role}`,
      "--data", `agent_purpose=${agentPurpose ?? ""}`,
      "--data", `model_provider=${modelProvider ?? ""}`,
      "--data", `model_name=${modelName ?? ""}`,
      "--data", `profile_name=${profileName ?? ""}`,
      "--data", `soul_tone=${soulTone ?? "direct"}`,
      "--data", `ticket_provider=${ticketProvider}`,
      "--data", `with_scrum_master=${withScrumMaster}`,
      "--trust",
      "--vcs-ref=HEAD",
    ];
    if (ctx.force) args.push("--overwrite");

    if (ctx.dryRun) {
      return {
        success: true,
        message: this.formatMessage(`Would run: copier ${args.join(" ")}`),
      };
    }

    // Ensure agents/hermes/ parent exists so copier doesn't have to create it
    // (copier handles this fine, but creating it ourselves lets us catch
    // permission issues earlier).
    mkdirSync(join(ctx.targetDir, "agents", "hermes"), { recursive: true });

    const spinner = p.spinner();
    spinner.start(`Running copier copy  (target: agents/hermes/${role})`);
    const result = spawnSync("copier", args, {
      stdio: "inherit",   // pass the interactive output through; copier prints its own progress
      env,
      cwd: ctx.targetDir,
    });
    spinner.stop(result.status === 0 ? "✓ copier run complete" : "✗ copier failed");

    if (result.status !== 0) {
      return {
        success: false,
        message: `✗ copier exited with status ${result.status}.  Check the output above; re-run with the same flags after fixing.`,
      };
    }

    return {
      success: true,
      message: `✓ Provisioned ${roleDir}  (runtime: gh:${ctx.runtimeRepo})`,
    };
  }
}
import { basename, join } from "node:path";
import { readFileSync } from "node:fs";
import * as p from "@clack/prompts";
import { Command, type InvokeResult } from "../Command";
import type { HermesAgentContext, TicketProvider } from "./types";
import {
  SOUL_TONES,
  ROLE_CHOICES,
  TICKET_PROVIDERS,
  deriveAgentId,
  deriveProfileName,
} from "./types";

/**
 * Synergy with CommonProject: if this repo was bootstrapped by the base
 * template, its board provider already lives in .project.json. Read it so the
 * recipe defaults to the SAME provider the repo's board was created in, rather
 * than blindly defaulting to plane.
 */
function detectTicketProvider(targetDir: string): TicketProvider | undefined {
  try {
    const t = JSON.parse(readFileSync(join(targetDir, ".project.json"), "utf8"))
      ?.ticket_provider?.type;
    return t === "plane" || t === "linear" || t === "trello" ? t : undefined;
  } catch {
    return undefined;
  }
}

/**
 * First step of the hermes-agent recipe. Either:
 *  - non-interactive (context.yes === true): apply sensible defaults relative
 *    to the current repo and short-circuit;
 *  - interactive: walk the user through a TUI (Clack) to collect missing fields.
 *
 * In both cases, mutates `this.context` (cast to HermesAgentContext) so that
 * downstream commands have what they need.
 */
export class PromptForAgentConfig extends Command {
  async invoke(): Promise<InvokeResult> {
    const ctx = this.context as HermesAgentContext;

    // Compute the default target_repo from the current working dir.
    // Lowercase here so the value is a valid hermes profile name, telegram
    // handle prefix, email local-part, and systemd unit slug — all of which
    // reject uppercase. GitHub repo names are case-insensitive, so this is safe.
    const defaultRepo = basename(ctx.targetDir).toLowerCase();
    const defaultRole = "pm";

    // --- Non-interactive shortcut ---
    if (ctx.yes) {
      ctx.targetRepo = (ctx.targetRepo ?? defaultRepo).toLowerCase();
      ctx.role ??= defaultRole;
      ctx.agentPurpose ??= `${ctx.role} agent for ${ctx.targetRepo}`;
      ctx.soulTone ??= "direct";
      ctx.modelProvider ??= "";
      ctx.modelName ??= "";
      // Board provider: honor an explicit flag, else inherit the repo's
      // existing .project.json provider, else plane.
      ctx.ticketProvider ??= detectTicketProvider(ctx.targetDir) ?? "plane";
      // A bare `pm` provision does not auto-add the sentinel unless asked.
      ctx.withScrumMaster ??= false;
      // In --yes mode we always skip the human-input pieces (BotFather, CF).
      ctx.skipTelegram ??= true;
      ctx.skipEmail ??= true;
      ctx.agentId = deriveAgentId(ctx.targetRepo!, ctx.role!);
      ctx.profileName = deriveProfileName(ctx.targetRepo!, ctx.role!);
      return {
        success: true,
        message: this.formatMessage(
          `✓ Non-interactive mode — using defaults  (repo=${ctx.targetRepo}, role=${ctx.role}, profile=${ctx.profileName})`
        ),
      };
    }

    // --- Interactive TUI ---
    p.intro("⚕  hermes-agent  ·  add a new agent role to this repo");

    // Pre-fill any values supplied via CLI flags; only prompt for what's missing.
    if (!ctx.targetRepo) {
      const answer = await p.text({
        message: "Target repo name",
        placeholder: defaultRepo,
        initialValue: defaultRepo,
        validate: (v) => (v && v.trim() ? undefined : "required"),
      });
      if (p.isCancel(answer)) return this.cancelled();
      ctx.targetRepo = String(answer).trim().toLowerCase();
    }

    if (!ctx.role) {
      const answer = await p.select({
        message: "Role",
        options: ROLE_CHOICES.map((r) => ({ value: r.value, label: r.label, hint: r.hint })),
        initialValue: defaultRole,
      });
      if (p.isCancel(answer)) return this.cancelled();
      ctx.role = String(answer).trim();
    }

    if (ctx.ticketProvider === undefined) {
      const detected = detectTicketProvider(ctx.targetDir);
      const answer = await p.select({
        message: "Ticket board provider",
        options: TICKET_PROVIDERS.map((t) => ({
          value: t.value,
          label: t.label,
          hint: t.value === detected ? `${t.hint} — current .project.json` : t.hint,
        })),
        initialValue: detected ?? "plane",
      });
      if (p.isCancel(answer)) return this.cancelled();
      ctx.ticketProvider = answer as TicketProvider;
    }

    // A PM owns the repo board; the Scrum Master is its continuous ticket
    // sentinel on the SAME board. Offer to provision both in one shot so the
    // pair is created together (identical end state to two separate runs).
    if (ctx.role === "pm" && ctx.withScrumMaster === undefined) {
      const answer = await p.confirm({
        message: "Also provision the paired Scrum Master (Ticket Sentinel) for this repo?",
        initialValue: true,
      });
      if (p.isCancel(answer)) return this.cancelled();
      ctx.withScrumMaster = answer === true;
    }

    if (!ctx.agentPurpose) {
      const answer = await p.text({
        message: "One-line purpose",
        placeholder: `${ctx.role} agent for ${ctx.targetRepo}`,
        initialValue: `${ctx.role} agent for ${ctx.targetRepo}`,
      });
      if (p.isCancel(answer)) return this.cancelled();
      ctx.agentPurpose = String(answer).trim();
    }

    if (!ctx.soulTone) {
      const answer = await p.select({
        message: "Personality tone",
        options: SOUL_TONES.map((t) => ({
          value: t,
          label: t,
          hint:
            t === "direct"
              ? "decision-forward, no preamble (default)"
              : t === "terse"
              ? "minimum words, conclusion-first"
              : t === "playful"
              ? "warm, mildly funny"
              : "precise, structured",
        })),
        initialValue: "direct",
      });
      if (p.isCancel(answer)) return this.cancelled();
      ctx.soulTone = answer as HermesAgentContext["soulTone"];
    }

    if (ctx.modelProvider === undefined) {
      const answer = await p.text({
        message: "Provider override (empty = inherit shared default profile)",
        placeholder: "",
      });
      if (p.isCancel(answer)) return this.cancelled();
      ctx.modelProvider = String(answer).trim();
    }

    if (ctx.modelName === undefined) {
      const answer = await p.text({
        message: "Model name override (empty = inherit shared default profile)",
        placeholder: "",
      });
      if (p.isCancel(answer)) return this.cancelled();
      ctx.modelName = String(answer).trim();
    }

    if (ctx.skipTelegram === undefined) {
      const wire = await p.confirm({
        message: `Wire up the Telegram bot (@${ctx.targetRepo}_${ctx.role}_bot) now?`,
        initialValue: true,
      });
      if (p.isCancel(wire)) return this.cancelled();
      ctx.skipTelegram = !wire;
    }

    if (ctx.skipEmail === undefined) {
      const wire = await p.confirm({
        message: `Provision the delo.sh email address (${ctx.targetRepo}-${ctx.role}@delo.sh) now?`,
        initialValue: true,
      });
      if (p.isCancel(wire)) return this.cancelled();
      ctx.skipEmail = !wire;
    }

    ctx.agentId = deriveAgentId(ctx.targetRepo!, ctx.role!);
    ctx.profileName = deriveProfileName(ctx.targetRepo!, ctx.role!);
    return {
      success: true,
      message: this.formatMessage(
        `✓ Collected agent config  (agent_id=${ctx.agentId}, profile=${ctx.profileName})`
      ),
    };
  }

  private cancelled(): InvokeResult {
    p.cancel("Aborted by user.");
    return { success: false, message: "Aborted by user." };
  }
}
# Hermes agent role manifest.  Tracked in the PROJECT repository.
# The agent's actual state (memory, sessions, evolving SOUL) lives in the
# runtime submodule.  This file is the immutable contract for this role.

repo: {{ target_repo }}
role: {{ role }}
agent_id: {{ agent_id }}
display_name: "{{ display_name }}"
purpose: "{{ agent_purpose }}"

# Inference target (empty = inherit from the shared default profile config).
model:
  provider: "{{ model_provider }}"
  name: "{{ model_name }}"

# Hermes profile name. ~/.hermes/profiles/<profile> is symlinked to ./runtime/.
profile: {{ profile_name }}

# Telegram bot identity (one bot per agent — see docs/architecture.md).
telegram:
  bot_username: "{{ bot_handle }}"

# Ticket-provider binding (linear | plane | trello).
# The Scrum Master sentinel talks ONLY to this via .scripts/lib/ticket-provider.sh;
# swapping providers is a one-line change here. Filled in by 42-ticket-provider.sh.
ticket_provider:
  name: {{ ticket_provider }}
  board_id: ""
  board_url: ""
{%- if ticket_provider == 'linear' %}
  team: ""        # Linear team key, e.g. DEL  (set before first sentinel run)
  project: ""     # optional Linear project name to scope milestones/issues
{%- elif ticket_provider == 'plane' %}
  workspace: "{{ plane_workspace }}"
  project: ""     # Plane project uuid (set by 42-ticket-provider.sh)
{%- elif ticket_provider == 'trello' %}
  board: ""       # Trello board id (set by 42-ticket-provider.sh)
{%- endif %}
  # Optional normalized-state name overrides for non-standard boards.
  in_review: ""   # e.g. "In Review"
  completed: ""   # e.g. "Done"

# Scrum Master sentinel knobs (only meaningful for role: scrum-master).
scrum_master:
  grace_hours: 0             # 0 = no human-approval wait (adversarially-reviewed review-lane = done); set >0 to require a wait
  auto_review: true          # autonomous adversarial review (act, do not wait) on/off
  paired_pm: "{{ target_repo }}-pm"

# Plane project (1:1 with this agent) — retained for fleet-registry back-compat.
plane:
  # Empty -> resolved from ~/.config/hermes-agent-template/config.toml [plane].workspace
  workspace: "{{ plane_workspace }}"
  # identifier is set by .scripts/42-ticket-provider.sh after creation (plane only)
  identifier: ""

# Bloodbank wiring (consumed + produced subjects).
bloodbank:
  subscribe:
    - "bloodbank.evt.v1.repo.{{ target_repo }}.>"
    - "bloodbank.cmd.v1.agent.{{ agent_id }}.>"
  producer: "hermes-agent:{{ agent_id }}"

# Runtime repo (git-tracked HERMES_HOME, auto-checkpointed).
runtime:
  # Empty owner -> resolved from config.toml [github].runtime_repo_owner.
  github_owner: "{{ runtime_repo_owner }}"
  github_repo: "{{ runtime_repo }}"
  submodule_path: "./runtime"
  checkpoint:
    cadence: "hourly"
    on_session_end: true

# Provenance — managed by the template, do not hand-edit.
provisioned_at: "{{ '%Y-%m-%dT%H:%M:%SZ' | strftime }}"
provisioned_by: hermes-agent-template
