        is_top_level = bool(line.strip()) and not line.startswith((" ", "\t"))
        if is_top_level and line.startswith(f"{key}:"):
            removing = True
            changed = True
            continue
        if removing and is_top_level:
            removing = False
        if not removing:
            new_lines.append(line)
