# profile.yaml — per-profile metadata (description, role, etc.)
# ---------------------------------------------------------------------------
#
# We keep this file deliberately tiny and separate from the profile's
# ``config.yaml``. ``config.yaml`` is the user-facing Hermes config
# (~5000 lines of defaults); ``profile.yaml`` is metadata ABOUT the
# profile itself (its role, who described it). Mixing them makes both
# harder to read.
#
# Missing file -> empty defaults; never an error. The kanban decomposer
# tolerates empty descriptions and just falls back to the profile name.


def _profile_yaml_path(profile_dir: Path) -> Path:
    return profile_dir / "profile.yaml"


def read_profile_meta(profile_dir: Path) -> dict:
    """Read ``<profile_dir>/profile.yaml`` and return a dict.

    Returns empty defaults when the file is missing or unreadable. Never raises — a corrupt
    profile.yaml on an unrelated profile must not break
    ``hermes profile list``.
    """
    empty = {"description": "", "description_auto": False, "config": {}}
    path = _profile_yaml_path(profile_dir)
    if not path.is_file():
        return dict(empty)
    try:
        import yaml
        with open(path, "r", encoding="utf-8") as f:
            data = yaml.safe_load(f) or {}
    except Exception:
        return dict(empty)
    if not isinstance(data, dict):
        return dict(empty)
    config_meta = data.get("config")
    if not isinstance(config_meta, dict):
        config_meta = {}
    return {
        "description": str(data.get("description") or "").strip(),
        "description_auto": bool(data.get("description_auto", False)),
        "config": {
            "inherit_from": config_meta.get("inherit_from"),
            "save_mode": config_meta.get("save_mode"),
        },
    }


def write_profile_meta(
    profile_dir: Path,
    *,
    description: Optional[str] = None,
    description_auto: Optional[bool] = None,
    config_inherit_from: object = _META_UNSET,
    config_save_mode: object = _META_UNSET,
) -> None:
    """Update ``<profile_dir>/profile.yaml`` in place.

    Only the explicitly passed fields are overwritten; unspecified
    fields preserve existing values. Creates the file if missing.
    Profile directory itself must exist.
    """
    if not profile_dir.is_dir():
        raise FileNotFoundError(f"profile directory does not exist: {profile_dir}")
    import yaml
    path = _profile_yaml_path(profile_dir)
    existing: dict = {}
    if path.is_file():
        try:
            with open(path, "r", encoding="utf-8") as f:
                loaded = yaml.safe_load(f) or {}
            if isinstance(loaded, dict):
                existing = loaded
        except Exception:
            existing = {}
    if description is not None:
        existing["description"] = description.strip()
    if description_auto is not None:
        existing["description_auto"] = bool(description_auto)
    if config_inherit_from is not _META_UNSET or config_save_mode is not _META_UNSET:
        config_meta = existing.get("config")
        if not isinstance(config_meta, dict):
            config_meta = {}

        if config_inherit_from is not _META_UNSET:
            if config_inherit_from is None:
                config_meta.pop("inherit_from", None)
            else:
                if config_inherit_from != "default":
                    raise ValueError("config inheritance currently supports only inherit_from='default'")
                config_meta["inherit_from"] = config_inherit_from

        if config_save_mode is not _META_UNSET:
            if config_save_mode is None:
                config_meta.pop("save_mode", None)
            else:
                if config_save_mode != "delta":
                    raise ValueError("config inheritance currently supports only save_mode='delta'")
                config_meta["save_mode"] = config_save_mode

        if config_meta:
            existing["config"] = config_meta
        else:
            existing.pop("config", None)
    with open(path, "w", encoding="utf-8") as f:
        yaml.safe_dump(existing, f, sort_keys=False, default_flow_style=False)


